/**
 * Provides a utility function to determine whether a graphic's origin is a [ParquetGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/ParquetGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a ParquetLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isParquetGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a ParquetLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a ParquetLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type ParquetGraphicOrigin from "./ParquetGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [ParquetGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/ParquetGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [ParquetGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/ParquetGraphicOrigin/), `false` otherwise.
 */
export function isParquetGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is ParquetGraphicOrigin;